// frontend/src/components/history/HistoryPanel.tsx
import React, { useState, useMemo } from 'react';
import { useAppDispatch, useAppSelector } from '../../store';
import { undo, redo, jumpTo } from '../../store/slices/historySlice';
import { formatDistanceToNow } from 'date-fns';
import { ru } from 'date-fns/locale';
import './HistoryPanel.css';

interface HistoryPanelProps {
  artifactId: number;
  onJump: (state: any) => void;
  onUndo?: () => void;
  onRedo?: () => void;
}

export const HistoryPanel: React.FC<HistoryPanelProps> = ({ 
  artifactId, 
  onJump,
  onUndo,
  onRedo
}) => {
  const dispatch = useAppDispatch();
  const { actions, currentActionId, isLoading } = useAppSelector(state => state.history);
  const [isOpen, setIsOpen] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');

  const getActionIcon = (type: string) => {
    const icons: Record<string, string> = {
      'add_node': '➕',
      'delete_node': '➖',
      'move_node': '↗️',
      'batch_move': '📦',
      'add_edge': '🔗',
      'delete_edge': '✂️',
      'edit_attribute': '✏️',
      'plugin_run': '🤖'
    };
    return icons[type] || '📌';
  };

  const handleUndo = async () => {
    if (onUndo) {
      onUndo();
    } else {
      const result = await dispatch(undo(artifactId)).unwrap();
      if (result?.state) {
        onJump(result.state);
      }
    }
  };

  const handleRedo = async () => {
    if (onRedo) {
      onRedo();
    } else {
      const result = await dispatch(redo(artifactId)).unwrap();
      if (result?.state) {
        onJump(result.state);
      }
    }
  };

  const handleJump = (action: HistoryAction) => {
    onJump(action.afterState);
  };

  // Фильтрация по поиску
  const filteredActions = useMemo(() => {
    if (!searchQuery.trim()) return actions;

    const query = searchQuery.toLowerCase();
    return actions.filter(action => 
      action.description.toLowerCase().includes(query) ||
      action.actionType.toLowerCase().includes(query)
    );
  }, [actions, searchQuery]);

  // Текущий индекс для подсветки
  const currentIndex = useMemo(() => {
    return actions.findIndex(a => a.id === currentActionId);
  }, [actions, currentActionId]);

  if (!isOpen) {
    return (
      <button 
        className="history-toggle" 
        onClick={() => setIsOpen(true)}
        title={`История (${actions.length} действий)`}
      >
        📋 {actions.length > 0 && <span className="history-count">{actions.length}</span>}
      </button>
    );
  }

  return (
    <div className="history-panel">
      <div className="history-header">
        <h3>
          История действий
          {isLoading && <span className="history-loading"> ⟳</span>}
        </h3>
        <div className="history-controls">
          <button 
            onClick={handleUndo} 
            disabled={currentIndex < 0 || isLoading}
            title="Отменить (Ctrl+Z)"
          >
            ↩️
          </button>
          <button 
            onClick={handleRedo} 
            disabled={currentIndex >= actions.length - 1 || isLoading}
            title="Повторить (Ctrl+Y)"
          >
            ↪️
          </button>
          <button onClick={() => setIsOpen(false)} title="Свернуть">
            ✕
          </button>
        </div>
      </div>

      {actions.length > 0 && (
        <div className="history-search">
          <input
            type="text"
            placeholder="🔍 Поиск в истории..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
        </div>
      )}

      <div className="history-list">
        {filteredActions.length === 0 ? (
          <div className="history-empty">
            {searchQuery ? 'Ничего не найдено' : 'Нет действий'}
          </div>
        ) : (
          [...filteredActions].reverse().map((action, idx) => {
            const originalIndex = actions.length - 1 - idx;
            const isCurrent = originalIndex === currentIndex;

            return (
              <div
                key={action.id}
                className={`history-item ${isCurrent ? 'current' : ''}`}
                onClick={() => handleJump(action)}
                title={action.description}
              >
                <span className="history-icon">{getActionIcon(action.actionType)}</span>
                <div className="history-content">
                  <span className="history-desc">{action.description}</span>
                  <span className="history-time">
                    {formatDistanceToNow(new Date(action.timestamp), { 
                      addSuffix: true,
                      locale: ru 
                    })}
                  </span>
                </div>
                {action.userType === 'plugin' && (
                  <span className="history-plugin">🤖</span>
                )}
              </div>
            );
          })
        )}
      </div>

      {actions.length > 0 && (
        <div className="history-footer">
          Всего: {actions.length} действий
        </div>
      )}
    </div>
  );
};

/* frontend/src/components/history/HistoryPanel.css */

.history-panel {
  position: fixed;
  bottom: 20px;
  right: 20px;
  width: 340px;
  background: var(--bg-secondary, #2d2d2d);
  border: 1px solid var(--border-color, #404040);
  border-radius: 8px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.5);
  z-index: 10000;
  display: flex;
  flex-direction: column;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  transition: all 0.3s ease;
}

/* Заголовок */
.history-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 12px 16px;
  background: var(--bg-tertiary, #363636);
  border-bottom: 1px solid var(--border-color, #404040);
  border-radius: 8px 8px 0 0;
}

.history-header h3 {
  margin: 0;
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary, #fff);
  display: flex;
  align-items: center;
  gap: 8px;
}

.history-position {
  font-size: 12px;
  font-weight: normal;
  color: var(--text-secondary, #aaa);
  background: var(--bg-secondary, #404040);
  padding: 2px 6px;
  border-radius: 12px;
}

.history-controls {
  display: flex;
  gap: 4px;
}

.history-btn {
  background: none;
  border: none;
  color: var(--text-primary, #fff);
  cursor: pointer;
  font-size: 16px;
  padding: 4px 8px;
  border-radius: 4px;
  transition: all 0.2s;
  opacity: 0.8;
}

.history-btn:hover:not(:disabled) {
  background: var(--bg-hover, #4a4a4a);
  opacity: 1;
}

.history-btn:disabled {
  opacity: 0.3;
  cursor: not-allowed;
}

/* Поиск */
.history-search {
  padding: 8px 12px;
  border-bottom: 1px solid var(--border-color, #404040);
}

.history-search-input {
  width: 100%;
  padding: 6px 10px;
  background: var(--bg-tertiary, #363636);
  border: 1px solid var(--border-color, #404040);
  border-radius: 4px;
  color: var(--text-primary, #fff);
  font-size: 12px;
  outline: none;
}

.history-search-input:focus {
  border-color: #2196f3;
}

.history-search-input::placeholder {
  color: var(--text-secondary, #888);
}

/* Список действий */
.history-list {
  max-height: 400px;
  overflow-y: auto;
  padding: 8px;
  scrollbar-width: thin;
  scrollbar-color: var(--border-color, #404040) var(--bg-secondary, #2d2d2d);
}

.history-list::-webkit-scrollbar {
  width: 6px;
}

.history-list::-webkit-scrollbar-track {
  background: var(--bg-secondary, #2d2d2d);
}

.history-list::-webkit-scrollbar-thumb {
  background-color: var(--border-color, #404040);
  border-radius: 3px;
}

/* Элемент истории */
.history-item {
  display: flex;
  align-items: flex-start;
  gap: 10px;
  padding: 10px 12px;
  margin: 4px 0;
  border-radius: 6px;
  cursor: pointer;
  background: var(--bg-tertiary, #363636);
  color: var(--text-primary, #fff);
  font-size: 12px;
  transition: all 0.2s;
  border-left: 3px solid transparent;
  position: relative;
}

.history-item:hover {
  background: var(--bg-hover, #404040);
  transform: translateX(-2px);
}

.history-item.current {
  background: var(--accent-blue, #2196f3);
  color: white;
  box-shadow: 0 2px 8px rgba(33, 150, 243, 0.3);
}

.history-item.current .history-meta {
  color: rgba(255, 255, 255, 0.8);
}

.history-icon {
  font-size: 16px;
  width: 24px;
  text-align: center;
  flex-shrink: 0;
}

.history-content {
  flex: 1;
  min-width: 0;
}

.history-description {
  font-weight: 500;
  margin-bottom: 2px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.history-meta {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 10px;
  color: var(--text-secondary, #aaa);
}

.history-time {
  flex: 1;
}

.history-plugin,
.history-group {
  font-size: 11px;
  opacity: 0.7;
}

.history-current-badge {
  margin-left: 8px;
  font-size: 14px;
  font-weight: bold;
}

/* Пустое состояние */
.history-empty,
.history-loading {
  padding: 20px;
  text-align: center;
  color: var(--text-secondary, #888);
  font-size: 12px;
  font-style: italic;
}

/* Футер */
.history-footer {
  padding: 8px 12px;
  border-top: 1px solid var(--border-color, #404040);
  font-size: 11px;
  color: var(--text-secondary, #aaa);
  display: flex;
  justify-content: space-between;
}

/* Свернутое состояние */
.history-toggle {
  position: fixed;
  bottom: 20px;
  right: 20px;
  width: 56px;
  height: 56px;
  border-radius: 50%;
  background: #2196f3;
  color: white;
  border: none;
  cursor: pointer;
  font-size: 24px;
  box-shadow: 0 4px 12px rgba(33, 150, 243, 0.5);
  z-index: 10000;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.3s ease;
}

.history-toggle:hover {
  transform: scale(1.1);
  box-shadow: 0 6px 16px rgba(33, 150, 243, 0.6);
}

.history-count {
  position: absolute;
  top: -5px;
  right: -5px;
  background: #f44336;
  color: white;
  font-size: 12px;
  padding: 2px 6px;
  border-radius: 10px;
  min-width: 20px;
  text-align: center;
}

/* Адаптивность */
@media (max-width: 768px) {
  .history-panel {
    width: 280px;
    bottom: 10px;
    right: 10px;
  }
}

