ter_state,\n            \"timestamp\": self.timestamp.isoformat() if self.timestamp else None,\n            \"user_type\": self.user_type,\n            \"description\": self.description,\n            \"plugin_id\": self.plugin_id,\n            \"group_id\": str(self.group_id) if self.group_id else None\n        }\n",
