-      "content": "// frontend/src/store/slices/historySlice.ts\nimport { createSlice, PayloadAction, createAsyncThunk } from '@reduxjs/toolkit';\nimport { api } from '../../services/api';\n\nexport interface HistoryAction {\n  id: string;\n  artifactId: number;\n  actionType: string;\n  beforeState: any;\n  afterState: any;\n  timestamp: string;\n  description: string;\n  userType?: 'user' | 'plugin';\n  pluginId?: string;\n  groupId?: string;\n}\n\ninterface HistoryState {\n  actions: HistoryAction[];\n  currentIndex: number;\n  isLoading: boolean;\n  error: string | null;\n}\n\nconst initialState: HistoryState = {\n  actions: [],\n  currentIndex: -1,\n  isLoading: false,\n  error: null\n};\n\n// ============================================================================\n// Async Thunks\n// ============================================================================\n\nexport const fetchHistory = createAsyncThunk(\n  'history/fetch',\n  async (artifactId: number, { rejectWithValue }) => {\n    try {\n      const response = await api.get(`/api/v2/artifacts/${artifactId}/history?limit=100`);\n      return { artifactId, actions: response.data };\n    } catch (error: any) {\n      return rejectWithValue(error.response?.data?.detail || 'Failed to fetch history');\n    }\n  }\n);\n\nexport const recordAction = createAsyncThunk(\n  'history/record',\n  async ({ \n    artifactId, \n    action \n  }: { \n    artifactId: number; \n    action: any;\n  }, { rejectWithValue }) => {\n    try {\n      const response = await api.post(`/api/v2/artifacts/${artifactId}/history/actions`, action);\n      return response.data;\n    } catch (error: any) {\n      return rejectWithValue(error.response?.data?.detail || 'Failed to record action');\n    }\n  }\n);\n\nexport const undo = createAsyncThunk(\n  'history/undo',\n  async (artifactId: number, { rejectWithValue }) => {\n    try {\n      const response = await api.post(`/api/v2/artifacts/${artifactId}/history/undo`);\n      return response.data;\n    } catch (error: any) {\n      if (error.response?.status === 404) {\n        return null;\n      }\n      return rejectWithValue(error.response?.data?.detail || 'Failed to undo');\n    }\n  }\n);\n\nexport const redo = createAsyncThunk(\n  'history/redo',\n  async (artifactId: number, { rejectWithValue }) => {\n    try {\n      const response = await api.post(`/api/v2/artifacts/${artifactId}/history/redo`);\n      return response.data;\n    } catch (error: any) {\n      if (error.response?.status === 404) {\n        return null;\n      }\n      return rejectWithValue(error.response?.data?.detail || 'Failed to redo');\n    }\n  }\n);\n\n// ============================================================================\n// Slice\n// ============================================================================\n\nconst historySlice = createSlice({\n  name: 'history',\n  initialState,\n  reducers: {\n    addLocalAction: (state, action: PayloadAction<HistoryAction>) => {\n      if (state.currentIndex < state.actions.length - 1) {\n        state.actions = state.actions.slice(0, state.currentIndex + 1);\n      }\n      state.actions.push(action.payload);\n      state.currentIndex = state.actions.length - 1;\n    },\n    \n    jumpToAction: (state, action: PayloadAction<number>) => {\n      if (action.payload >= 0 && action.payload < state.actions.length) {\n        state.currentIndex = action.payload;\n      }\n    },\n    \n    resetHistory: (state) => {\n      state.actions = [];\n      state.currentIndex = -1;\n      state.error = null;\n    },\n    \n    clearError: (state) => {\n      state.error = null;\n    }\n  },\n  extraReducers: (builder) => {\n    builder\n      // Fetch History\n      .addCase(fetchHistory.pending, (state) => {\n        state.isLoading = true;\n        state.error = null;\n      })\n      .addCase(fetchHistory.fulfilled, (state, action) => {\n        state.isLoading = false;\n        state.actions = action.payload.actions;\n        state.currentIndex = action.payload.actions.length - 1;\n      })\n      .addCase(fetchHistory.rejected, (state, action) => {\n        state.isLoading = false;\n        state.error = action.payload as string;\n      })\n      \n      // Record Action\n      .addCase(recordAction.fulfilled, (state, action) => {\n        if (state.currentIndex < state.actions.length - 1) {\n          state.actions = state.actions.slice(0, state.currentIndex + 1);\n        }\n        state.actions.push(action.payload);\n        state.currentIndex = state.actions.length - 1;\n      })\n      \n      // Undo\n      .addCase(undo.fulfilled, (state, action) => {\n        if (action.payload) {\n          state.currentIndex = Math.max(-1, state.currentIndex - 1);\n        }\n      });\n  }\n});\n\nexport const { addLocalAction, jumpToAction, resetHistory, clearError } = historySlice.actions;\nexport default historySlice.reducer;\n",
