     "frontend/src/store/slices/projectsSlice.ts": {
       "content": "// store/slices/projectsSlice.ts\nimport { createSlice, createAsyncThunk, PayloadAction } from '@reduxjs/toolkit';\nimport { api } from '../../services/api';\n\nexport interface Project {\n  id: number;\n  name: string;\n  description?: string;\n  created_at: string;\n  updated_at: string;\n}\n\ninterface ProjectsState {\n  projects: Project[];\n  currentProject: Project | null;\n  isLoading: boolean;\n  error: string | null;\n}\n\nconst initialState: ProjectsState = {\n  projects: [],\n  currentProject: null,\n  isLoading: false,\n  error: null,\n};\n\nexport const fetchProjects = createAsyncThunk(\n  'projects/fetchAll',\n  async () => {\n    console.log('[Projects] Fetching all projects');\n    const response = await api.get('/api/v1/projects');\n    return response;\n  }\n);\n\nconst projectsSlice = createSlice({\n  name: 'projects',\n  initialState,\n  reducers: {\n    setCurrentProject: (state, action: PayloadAction<number>) => {\n      const project = state.projects.find(p => p.id === action.payload);\n      if (project) {\n        state.currentProject = project;\n        console.log('[Projects] Current project set to:', project.id, project.name);\n      } else {\n        console.warn('[Projects] Project not found:', action.payload);\n      }\n    },\n  },\n  extraReducers: (builder) => {\n    builder\n      .addCase(fetchProjects.pending, (state) => {\n        state.isLoading = true;\n      })\n      .addCase(fetchProjects.fulfilled, (state, action) => {\n        state.isLoading = false;\n        state.projects = action.payload;\n        console.log('[Projects] Loaded projects:', action.payload.length);\n      })\n      .addCase(fetchProjects.rejected, (state, action) => {\n        state.isLoading = false;\n        state.error = action.error.message || 'Failed to fetch projects';\n      });\n  },\n});\n\nexport const { setCurrentProject } = projectsSlice.actions;\nexport default projectsSlice.reducer;",
